import React from 'react';

import { HeadFC, navigate } from 'gatsby';
import { SETTINGS_DATA } from 'config/data';

import Layout from 'hoc/Layout/Layout';
import Settings from 'containers/Settings/Settings';
import Seo from 'hoc/Seo/Seo';

import X from 'assets/icons/close.svg';

import * as classes from './Account.module.scss';

const Account = () => {
	function backHandler() {
		navigate(-1);
	}

	return (
		<Layout>
			<Settings data={SETTINGS_DATA} actions={<X className={classes.X} onClick={backHandler} />}>
				hello
			</Settings>
		</Layout>
	);
};

export default Account;

export const Head: HeadFC = () => <Seo>Account</Seo>;
